import {
  Routes,
  Route,
  BrowserRouter,
  Outlet,
  Navigate,
  useLocation,
} from "react-router-dom";
import ScrollToTop from "../components/ScrollToTop/ScrollToTop";
import RoutesList from "../constants/RoutesList";
import Home from "../pages/Home/Home";
import Login from "../pages/Login/Login";

import ProductsList from "../pages/Products/ProductsList";
import ProductDetails from "../pages/Products/ProductDetails";
import ProductForm from "../pages/Products/ProductForm";
import CategoriesList from "../pages/Categories/CategoriesList";
import CategoryForm from "../pages/Categories/CategoriesForm";
import DesignsList from "../pages/Designs/DesignsList";
import DesignForm from "../pages/Designs/DesignsForm";
import ColorsList from "../pages/Colors/ColorsList";
import ColorForm from "../pages/Colors/ColorForm";
import SizesList from "../pages/Sizes/SizesList";
import SizeForm from "../pages/Sizes/SizeForm";
// import UsersList from '../pages/Users/List';
// import UserDetails from '../pages/Users/Details';
// import UserProfile from '../pages/Users/Profile';
// import UserProfileUpdate from '../pages/Users/Update';
// import HolidaysList from '../pages/Holidays/List';
// import HolidayUpdate from '../pages/Holidays/Update';
// import DepartmentsList from '../pages/Departments/List';
// import WikiList from '../pages/Wikis/List';
// import WikiDetails from '../pages/Wikis/Details';
// import LeadsList from '../pages/Leads/List';
// import LeadDetails from '../pages/Leads/Details';
// import LeadForm from '../pages/Leads/Form';
// import ClientsList from '../pages/Clients/List';
// import ClientDetails from '../pages/Clients/Details';
// import ClientForm from '../pages/Clients/Form';
// import ProjectForm from '../pages/Projects/Form';
// import ProjectDetails from '../pages/Projects/Details';
// import ProjectsList from '../pages/Projects/List';
// import NewsletterDetails from '../pages/Newsletter/Details';
// import NewsletterForm from '../pages/Newsletter/Form';
// import NewsletterList from '../pages/Newsletter/List';
// import NewsletterRedirect from "../pages/Newsletter/Track";
// import SubscriberDetails from '../pages/SubscriberNewsletter/Details'
// import SubscriberList from '../pages/SubscriberNewsletter/List'
// import SubsciberForm from '../pages/SubscriberNewsletter/Form'

const ProtectedRoute = ({ children }) => {
  let location = useLocation();

  if (!localStorage.getItem("Token")) {
    return <Navigate to="/" state={{ from: location }} replace />;
  }
  return children;
};

export default ProtectedRoute;
export const Router = () => {
  return (
    <BrowserRouter>
      <ScrollToTop />
      <Routes>
        <Route element={<Outlet />}>
          <Route path={RoutesList.login} element={<Login />} />
          <Route
            index
            path={RoutesList.home}
            element={
              <Home />
            }
          />

          <Route
            path={RoutesList.products}
            element={
              <ProductsList />
            }
          />
          <Route
            path={`${RoutesList.products}/:id`}
            element={
              <ProductDetails />
            }
          />

          <Route path="/products/new" element={<ProductForm />} />
          <Route path="/products/:id/edit" element={<ProductForm />} />

          <Route path="/categories" element={<CategoriesList />} />
          <Route path="/categories/new" element={<CategoryForm />} />
          <Route path="/categories/:id/edit" element={<CategoryForm />} />

          <Route path="/designs" element={<DesignsList />} />
          <Route path="/designs/new" element={<DesignForm />} />
          <Route path="/designs/:id/edit" element={<DesignForm />} />

          <Route path="/colors" element={<ColorsList />} />
          <Route path="/colors/new" element={<ColorForm />} />
          <Route path="/colors/:id/edit" element={<ColorForm />} />

          <Route path="/sizes" element={<SizesList />} />
          <Route path="/sizes/new" element={<SizeForm />} />
          <Route path="/sizes/:id/edit" element={<SizeForm />} />

          {/* User routes   */}
          {/* <Route path={RoutesList.users} element={<UsersList />} />
          <Route path={`${RoutesList.users}/:id`} element={<UserDetails />} />
          <Route path={RoutesList.userProfile} element={<UserProfile />} />
          <Route
            path={RoutesList.userProfileUpdate}
            element={<UserProfileUpdate />}
          />

          <Route path={RoutesList.holidays} element={<HolidaysList />} />
          <Route
            path={`${RoutesList.holidays}/:id/edit`}
            element={<HolidayUpdate />}
          />

          <Route path={RoutesList.departments} element={<DepartmentsList />} />

          <Route path={RoutesList.leads} element={<LeadsList />} />
          <Route path={`${RoutesList.leads}/:id`} element={<LeadDetails />} />
          <Route path={RoutesList.leadCreate} element={<LeadForm />} />
          <Route path={`${RoutesList.leads}/:id/edit`} element={<LeadForm />} />

          <Route path={RoutesList.wikis} element={<WikiList />} />
          <Route path={`${RoutesList.wikis}/:id`} element={<WikiDetails />} />

          <Route path={RoutesList.clients} element={<ClientsList />} />
          <Route
            path={`${RoutesList.clients}/:id`}
            element={<ClientDetails />}
          />
          <Route path={RoutesList.clientCreate} element={<ClientForm />} />
          <Route
            path={`${RoutesList.clients}/:id/edit`}
            element={<ClientForm />}
          />

          <Route path={RoutesList.projects} element={<ProjectsList />} />
          <Route
            path={`${RoutesList.projects}/:id`}
            element={<ProjectDetails />}
          />
          <Route path={RoutesList.projectCreate} element={<ProjectForm />} />
          <Route
            path={`${RoutesList.projects}/:id/edit`}
            element={<ProjectForm />}
          />

          <Route path={RoutesList.newsletters} element={<NewsletterList />} />
          <Route
            path={`${RoutesList.newsletters}/:id`}
            element={<NewsletterDetails />}
          />
          <Route
            path={RoutesList.newslettersCreate}
            element={<NewsletterForm />}
          />
          <Route
            path={`${RoutesList.newsletters}/:id/edit`}
            element={<NewsletterForm />}
          />

          <Route path={RoutesList.track} element={<NewsletterRedirect />} />

          <Route path={RoutesList.subscriber} element={<SubscriberList />} />
          <Route
            path={`${RoutesList.subscriber}/:id`}
            element={<SubscriberDetails />}
          />
          <Route
            path={RoutesList.subscriberCreate}
            element={<SubsciberForm />}
          /> */}
        </Route>
      </Routes>
    </BrowserRouter>
  );
};
